import React from 'react';
import { Link } from 'react-router-dom';

function Dashboard() {
  return (
    <div className="dashboard">
      <h2>Dashboard</h2>
      <Link to="/projects">View Projects</Link>
      <Link to="/tasks">View Tasks</Link>
    </div>
  );
}

export default Dashboard;
